def validate_credit_card_number(card_number: str) -> str:
    """
    Validate and sanitize a credit card number.
    
    Args:
        card_number: The credit card number (may contain spaces or dashes).
        
    Returns:
        Sanitized card number (digits only).
        
    Raises:
        ValueError: If the card number is invalid.
    """
    if not card_number or not isinstance(card_number, str):
        raise ValueError("Card number must be a non-empty string.")

    # Remove spaces and dashes
    sanitized = re.sub(r'[\s\-]', '', card_number)

    # Check that it's all digits
    if not sanitized.isdigit():
        raise ValueError("Card number must contain only digits, spaces, or dashes.")

    # Check length (most cards are 13-19 digits)
    if not (13 <= len(sanitized) <= 19):
        raise ValueError("Card number must be between 13 and 19 digits.")

    # Luhn algorithm check
    if not _luhn_check(sanitized):
        raise ValueError("Card number fails Luhn check - invalid card number.")

    return sanitized


def _luhn_check(card_number: str) -> bool:
    """Validate a card number using the Luhn algorithm."""
    digits = [int(d) for d in card_number]
    digits.reverse()

    checksum = 0
    for i, digit in enumerate(digits):
        if i % 2 == 1:
            digit *= 2
            if digit > 9:
                digit -= 9
        checksum += digit

    return checksum % 10 == 0


