def get_masked_card_number(card_number: str) -> str:
    """
    Return a masked version of the card number for display purposes.
    Only shows the last 4 digits.
    
    Args:
        card_number: The full card number (plain text).
        
    Returns:
        Masked card number like "****-****-****-1234"
    """
    sanitized = re.sub(r'[\s\-]', '', card_number)
    if len(sanitized) < 4:
        return "****"
    last_four = sanitized[-4:]
    masked_length = len(sanitized) - 4
    groups = []
    remaining = masked_length
    while remaining > 0:
        group_size = min(4, remaining)
        groups.append('*' * group_size)
        remaining -= group_size
    groups.append(last_four)
    return '-'.join(groups)


